} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:17px\">今日では、木の重要性はかつてないほど高まっています。10,000種類以上の製品が木から作られていると言われています。化学の力を借りれば、テキサスの木が斧で切り倒されたときには想像もつかなかったような化学物質やプラスチックや繊維が、何の変哲もない材木から生み出されます。</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"className\":\"is-style-fill\"} -->\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link wp-element-button\">さらに詳しく</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:media-text --></div></div>\n<!-- /wp:cover -->\";}i:25;O:8:\"stdClass\":7:{s:2:\"id\";i:1231;s:5:\"title\";O:8:\"stdClass\":1:{s:8:\"rendered\";s:48:\"右に画像付きのメディアとテキスト\";}s:7:\"content\";O:8:\"stdClass\":2:{s:8:\"rendered\";s:805:\"\n<div class=\"wp-block-media-text alignfull has-media-on-the-right is-stacked-on-mobile is-vertically-aligned-center is-style-default\" style=\"grid-template-columns:auto 56%\"><div class=\"wp-block-media-text__content\">\n<h2 class=\"wp-block-heading has-text-color\" style=\"color:#000000\"><strong>青い海の岸辺</strong></h2>\n\n\n\n<p class=\"has-text-color wp-block-paragraph\" style=\"color:#636363;font-size:17px;line-height:1.1\">エレノア・ハリス&nbsp;(アメリカ合衆国, 1901年〜1942年)</p>\n</div><figure class=\"wp-block-media-text__media\"><img decoding=\"async\" src=\"https://s.w.org/images/core/5.8/art-02.jpg\" alt=\"油絵の具で作られた、明るい青い海とわずかに曇りの空につながる緑と茶色の田園風景。 \" /></figure></div>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:9:\"protected\";b:0;}s:4:\"meta\";O:8:\"stdClass\":10:{s:14:\"_crdt_document\";s:0:\"\";s:31:\"jetpack_post_was_ever_published\";b:0;s:13:\"wpop_keywords\";s:0:\"\";s:16:\"wpop_description\";s:90:\"右側に画像、左側にテキストがあるメディアとテキストブロック。\";s:19:\"wpop_viewport_width\";i:1200;s:16:\"wpop_block_types\";a:1:{i:0;s:0:\"\";}s:11:\"wpop_locale\";s:2:\"ja\";s:15:\"wpop_wp_version\";s:0:\"\";s:25:\"wpop_contains_block_types\";s:43:\"core/heading,core/media-text,core/paragraph\";s:9:\"footnotes\";s:0:\"\";}s:14:\"category_slugs\"